const items = $input.all();
const lead = items[0].json;

const newLead = {
  id: Date.now(),
  fecha: lead.fecha,
  fuente: lead.fuente,
  primer_mensaje: lead.primer_mensaje,
  ultimo_mensaje: lead.ultimo_mensaje,
  total_mensajes: lead.total_mensajes,
  conversacion: lead.conversacion,
  status: 'nuevo'
};

return [{ json: newLead }];

