parameters.jsCode:
const lead = $('Formatear Lead').first().json;
const raw = $input.all()[0].json;

let extracted = {};
try {
  const content = raw.choices && raw.choices[0] && raw.choices[0].message && raw.choices[0].message.content;
  extracted = content ? JSON.parse(content) : {};
} catch (e) {
  extracted = {};
}

return [{
  json: {
    fecha: lead.fecha,
    fuente: lead.fuente,
    primer_mensaje: lead.primer_mensaje,
    ultimo_mensaje: lead.ultimo_mensaje,
    total_mensajes: lead.total_mensajes,
    nombre: extracted.nombre || 'No detectado',
    whatsapp: extracted.whatsapp || 'No detectado',
    negocio: extracted.negocio || 'No detectado',
    problema: extracted.problema || 'No detectado',
    solucion: extracted.solucion || 'No detectada'
  }
}];

